// frontend/src/pages/UploadResume.js
import React, { useState } from 'react';
import axios from 'axios';

const UploadResume = () => {
  const [resumeText, setResumeText] = useState('');
  const [uploading, setUploading] = useState(false);
  const [message, setMessage] = useState('');
  const token = localStorage.getItem('token');

  const handleUpload = async () => {
    if (!resumeText) {
      setMessage('Please paste your resume text');
      return;
    }

    setUploading(true);
    try {
      const response = await axios.post(
        'http://localhost:5000/api/applications',
        {
          jobTitle: 'Resume Upload',
          companyName: 'Self',
          resumeText: resumeText,
          status: 'Draft'
        },
        { headers: { 'x-auth-token': token } }
      );
      setMessage('✅ Resume uploaded successfully!');
      setResumeText('');
    } catch (error) {
      setMessage('❌ Error uploading resume');
      console.error(error);
    }
    setUploading(false);
  };

  return (
    <div style={{ padding: '20px', maxWidth: '800px', margin: '0 auto' }}>
      <h1>📄 Upload Your Resume</h1>
      
      <div style={{ marginBottom: '20px' }}>
        <label style={{ display: 'block', marginBottom: '10px', fontWeight: 'bold' }}>
          Paste your resume text here:
        </label>
        <textarea
          rows={15}
          value={resumeText}
          onChange={(e) => setResumeText(e.target.value)}
          placeholder="Paste your resume content here...
          
Example:
Experienced Python Developer with 5+ years experience.
Skills: Python, Django, React, SQL, AWS
Education: B.Tech in Computer Science
Experience: Software Engineer at Tech Corp"
          style={{
            width: '100%',
            padding: '10px',
            border: '1px solid #ddd',
            borderRadius: '5px',
            fontFamily: 'monospace'
          }}
        />
      </div>

      <button
        onClick={handleUpload}
        disabled={uploading}
        style={{
          padding: '10px 20px',
          background: '#007bff',
          color: 'white',
          border: 'none',
          borderRadius: '5px',
          cursor: 'pointer'
        }}
      >
        {uploading ? 'Uploading...' : '📤 Upload Resume'}
      </button>

      {message && (
        <div style={{
          marginTop: '20px',
          padding: '10px',
          background: message.includes('✅') ? '#d4edda' : '#f8d7da',
          color: message.includes('✅') ? '#155724' : '#721c24',
          borderRadius: '5px'
        }}>
          {message}
        </div>
      )}

      <div style={{ marginTop: '30px', padding: '15px', background: '#f5f5f5', borderRadius: '10px' }}>
        <h3>📝 Sample Resume (Copy-Paste to Test)</h3>
        <pre style={{ whiteSpace: 'pre-wrap', fontSize: '12px' }}>
{`John Doe
Software Engineer

Summary:
Experienced Python Developer with 5+ years of experience in full-stack development.

Skills:
- Programming: Python, JavaScript, Java
- Frameworks: Django, React, Flask
- Databases: PostgreSQL, MongoDB
- Cloud: AWS (EC2, S3, Lambda)
- Tools: Git, Docker, Jenkins

Experience:
Senior Software Engineer | Tech Corp (2020-Present)
- Developed REST APIs using Django and Django REST Framework
- Built React frontend components for dashboard
- Deployed applications on AWS

Education:
B.Tech in Computer Science | University Name (2015-2019)

Certifications:
- AWS Certified Developer
- Python Professional Certificate`}
        </pre>
        <button
          onClick={() => setResumeText(`John Doe
Software Engineer

Summary:
Experienced Python Developer with 5+ years of experience in full-stack development.

Skills:
- Programming: Python, JavaScript, Java
- Frameworks: Django, React, Flask
- Databases: PostgreSQL, MongoDB
- Cloud: AWS (EC2, S3, Lambda)
- Tools: Git, Docker, Jenkins

Experience:
Senior Software Engineer | Tech Corp (2020-Present)
- Developed REST APIs using Django and Django REST Framework
- Built React frontend components for dashboard
- Deployed applications on AWS

Education:
B.Tech in Computer Science | University Name (2015-2019)`)}
          style={{
            marginTop: '10px',
            padding: '5px 10px',
            background: '#28a745',
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            cursor: 'pointer'
          }}
        >
          📋 Use Sample Resume
        </button>
      </div>
    </div>
  );
};

export default UploadResume;
